import { useState, useCallback } from "react";
import { sendChat, transcribeAudio } from "../api";

const INITIAL = [{
  role: "assistant",
  content: "ARIA online. I'm monitoring 7 AI models across your plant fleet — " +
           "forecasting, demand, energy, anomaly detection, plant behavior, " +
           "predictive maintenance, and failure prediction. Ask me anything."
}];

export function useChat() {
  const [messages, setMessages] = useState(INITIAL);
  const [loading,  setLoading]  = useState(false);

  const send = useCallback(async (text) => {
    if (!text?.trim()) return;
    const userMsg = { role: "user", content: text };
    setMessages(prev => [...prev, userMsg]);
    setLoading(true);
    try {
      const reply = await sendChat(text, [...messages, userMsg]);
      setMessages(prev => [...prev, { role: "assistant", content: reply }]);
    } catch {
      setMessages(prev => [...prev, {
        role: "assistant",
        content: "Connection error. Please verify the backend is running on port 8000."
      }]);
    }
    setLoading(false);
  }, [messages]);

  const sendVoice = useCallback(async (audioB64) => {
    try {
      const text = await transcribeAudio(audioB64);
      if (text) await send(text);
      else await send("(voice transcription returned empty — please type your question)");
    } catch {
      await send("(voice transcription failed — please type your question)");
    }
  }, [send]);

  const clear = useCallback(() => setMessages(INITIAL), []);

  return { messages, loading, send, sendVoice, clear };
}
